html:
{%- macro add_header(page_num, max_pages, doc, letter_head, no_letterhead, footer, print_settings=None,
print_heading_template=None) -%}
{%- endmacro -%}

{%- macro format_vn_num(val) -%}
{%- if val is none -%}
0
{%- else -%}
{%- set val_float = val | flt -%}
{%- set formatted = "{:,.4f}".format(val_float) | replace(",", "TEMP") | replace(".", ",") | replace("TEMP", ".") -%}
{{ formatted.rstrip("0").rstrip(",") }}
{%- endif -%}
{%- endmacro -%}

{% set trans_date = frappe.utils.getdate(doc.transaction_date or frappe.utils.today()) %}
{% set company_doc = frappe.get_doc("Company", doc.company) %}
{% set company_address_name = frappe.db.get_value("Address", {"link_doctype": "Company", "link_name": doc.company,
"is_primary_address": 1}, "name") %}
{% if not company_address_name %}
{% set company_address_name = frappe.db.get_value("Address", {"link_doctype": "Company", "link_name": doc.company},
"name") %}
{% endif %}
{% set company_address_display = "" %}
{% if company_address_name %}
{% set company_address_doc = frappe.get_doc("Address", company_address_name) %}
{% set addr_parts = [] %}
{% if company_address_doc.address_line1 %}{% set _ = addr_parts.append(company_address_doc.address_line1) %}{% endif %}
{% if company_address_doc.address_line2 %}{% set _ = addr_parts.append(company_address_doc.address_line2) %}{% endif %}
{% if company_address_doc.city %}{% set _ = addr_parts.append(company_address_doc.city) %}{% endif %}
{% if company_address_doc.state %}{% set _ = addr_parts.append(company_address_doc.state) %}{% endif %}
{% if company_address_doc.country %}{% set _ = addr_parts.append(company_address_doc.country) %}{% endif %}
{% set company_address_display = addr_parts | join(", ") %}
{% endif %}

<style>
    /* Ghi đè padding và kích thước của trang in Frappe để hiển thị khổ ngang trên cả màn hình và bản in */
    body {
        padding: 0 !important;
        margin: 0 !important;
    }

    .print-format,
    .print-format-builder {
        width: 297mm !important;
        /* Khổ ngang A4 trên màn hình */
        max-width: 297mm !important;
        /* Ghi đè giới hạn max-width của Portrait (8.3in) */
        min-height: 210mm !important;
        padding: 6mm !important;
        margin: auto !important;
        orientation: landscape;
        /* Cung cấp tùy chọn landscape cho PDF generator của Frappe */
    }

    @media print {
        @page {
            size: A4 landscape;
            margin: 6mm;
        }

        .print-format,
        .print-format-builder {
            width: 100% !important;
            max-width: 100% !important;
            min-height: auto !important;
            padding: 0 !important;
            margin: 0 !important;
        }
    }

    .dego-po-container {
        font-family: "Arial", sans-serif;
        color: #000;
        line-height: 1.3;
        padding: 0;
        font-size: 10px;
    }

    .gold-top-bar {
        height: 4px;
        background-color: #f1a417;
        /* Gold/yellow color matching the top border */
        margin-bottom: 8px;
    }

    .company-header {
        margin-bottom: 10px;
    }

    .company-name {
        font-weight: bold;
        font-size: 13px;
        color: #000;
    }

    .company-detail {
        font-size: 10px;
        color: #333;
    }

    .supplier-info {
        margin-top: 8px;
        margin-bottom: 8px;
        font-size: 10px;
    }

    .document-title {
        text-align: center;
        font-size: 16px;
        font-weight: bold;
        margin-top: 8px;
        margin-bottom: 8px;
        letter-spacing: 1px;
    }

    .document-no {
        color: red;
        font-size: 10px;
        font-weight: bold;
        margin-top: 3px;
    }

    .po-items-table {
        width: 100%;
        border-collapse: collapse;
        margin-bottom: 8px;
        font-size: 9px;
        table-layout: fixed;
        word-wrap: break-word;
    }

    .po-items-table th,
    .po-items-table td {
        border: 1px solid #000;
        padding: 3px 2px;
        vertical-align: middle;
        word-break: break-word;
    }

    .po-items-table th {
        background-color: #e2efda;
        /* Pastel green from Excel */
        font-weight: bold;
        text-align: center;
        font-size: 9px;
    }

    .po-items-table tr.total-row td {
        background-color: #f2f2f2;
    }

    .item-description {
        font-size: 9px;
        color: #555;
        font-style: italic;
    }

    .agreements-section {
        margin-top: 10px;
        font-size: 10px;
    }

    .agreement-title {
        font-weight: bold;
        font-style: italic;
        margin-bottom: 5px;
    }

    .agreement-item {
        margin-bottom: 4px;
    }

    .item-num {
        font-weight: bold;
    }

    .item-val {
        margin-left: 5px;
    }

    .sub-item {
        margin-left: 20px;
        margin-top: 3px;
    }

    .attached-info {
        margin-top: 12px;
    }

    .signature-section {
        margin-top: 15px;
        page-break-inside: avoid;
        font-size: 10px;
    }

    .signature-date {
        text-align: right;
        font-style: italic;
        margin-bottom: 10px;
        padding-right: 5%;
    }

    .signature-table {
        width: 100%;
        border-collapse: collapse;
    }

    .signature-table td {
        border: none !important;
    }

    .nowrap-col {
        white-space: nowrap;
    }
</style>

<script>
    (function () {
        function applyLandscapeStyles() {
            /* Tìm phần tử .print-format (wrapper chính của Frappe) */
            var pf = document.querySelector('.print-format') || document.querySelector('.print-format-builder');
            if (pf) {
                pf.classList.add('landscape');
                pf.style.setProperty('width', '297mm', 'important');
                pf.style.setProperty('max-width', '297mm', 'important');
                /* GHI ĐÈ min-height: 11.69in (chiều cao Portrait) của standard.css
                   thành 210mm (chiều cao Landscape) để trang hiển thị đúng tỷ lệ A4 ngang */
                pf.style.setProperty('min-height', '210mm', 'important');
            }
            try {
                if (window.parent && window.parent !== window) {
                    var parentDoc = window.parent.document;
                    var iframes = parentDoc.querySelectorAll('iframe');
                    for (var i = 0; i < iframes.length; i++) {
                        if (iframes[i].contentWindow === window) {
                            var iframe = iframes[i];
                            iframe.style.setProperty('width', '100%', 'important');
                            iframe.style.setProperty('max-width', '297mm', 'important');
                            var current = iframe.parentElement;
                            while (current) {
                                if (current.classList.contains('print-format-container') ||
                                    current.classList.contains('print-preview') ||
                                    current.classList.contains('pdf-viewer')) {
                                    current.style.setProperty('width', '100%', 'important');
                                    current.style.setProperty('max-width', '297mm', 'important');
                                }
                                current = current.parentElement;
                            }
                        }
                    }
                }
            } catch (e) {
                console.warn("Parent iframe styling skipped", e);
            }
        }
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', applyLandscapeStyles);
        } else {
            applyLandscapeStyles();
        }
    })();
</script>

<div class="dego-po-container">
    <!-- Top Gold Border Line -->
    <div class="gold-top-bar"></div>

    <!-- Company Info Header -->
    <div class="company-header">
        <div class="company-name">{{ (company_doc.company_name or doc.company) | upper }}</div>
        <div class="company-detail">Địa chỉ: {{ company_address_display or "Chưa cấu hình địa chỉ công ty" }}</div>
        <div class="company-detail">Mã số thuế: {{ company_doc.tax_id or "" }}</div>
    </div>

    <!-- Supplier Recipient -->
    <div class="supplier-info">
        <div><strong>Kính gửi:</strong> {{ (doc.supplier_name or "") | upper }}</div>
        <div><strong>Địa chỉ:</strong> {{ doc.address_display or "" }}</div>
    </div>

    <!-- Document Title -->
    <div class="document-title">
        ĐƠN ĐẶT HÀNG
        <div class="document-no">Số: {{ doc.name }}</div>
    </div>

    <!-- Items Table -->
    <table class="po-items-table">
        <thead>
            <tr>
                <th style="width: 3%; text-align: center;" class="nowrap-col">STT</th>
                <th style="width: 7%; text-align: center;">Mã</th>
                <th style="width: 16%; text-align: left;">Tên hàng hóa</th>
                <th style="width: 11%; text-align: left;">Xuất xứ/ TSKT/ chất liệu</th>
                <th style="width: 4%; text-align: center;" class="nowrap-col">ĐVT</th>
                <th style="width: 5%; text-align: right;" class="nowrap-col">SL</th>
                <th style="width: 9%; text-align: right;">Đơn giá (Chưa VAT)</th>
                <th style="width: 4%; text-align: center;" class="nowrap-col">VAT</th>
                <th style="width: 9%; text-align: right;">Đơn giá (Đã VAT)</th>
                <th style="width: 10%; text-align: right;">Thành tiền</th>
                <th style="width: 8%; text-align: left;">Kho nhận</th>
                <th style="width: 7%; text-align: left;">Tên trên HĐ</th>
                <th style="width: 7%; text-align: left;">Ghi chú</th>
            </tr>
        </thead>
        <tbody>
            {% for item in doc.items %}
            {% set tax_map = frappe.utils.parse_json(item.item_tax_rate or '{}') %}
            {% set tax_rate = 0 %}
            {% for account, rate in tax_map.items() %}
            {% set tax_rate = rate %}
            {% endfor %}
            {% if tax_rate == 0 %}
            {% for tax in doc.taxes %}
            {% if tax.charge_type == "On Net Total" and tax.rate %}
            {% set tax_rate = tax.rate %}
            {% endif %}
            {% endfor %}
            {% endif %}

            {% set rate_with_vat = item.rate * (1 + tax_rate / 100) %}
            {% set amount_with_vat = item.qty * item.rate * (1 + tax_rate / 100) %}

            <tr>
                <td style="text-align: center;" class="nowrap-col">{{ loop.index }}</td>
                <td style="text-align: center;" class="nowrap-col">{{ item.item_code }}</td>
                <td style="text-align: left;">{{ item.item_name }}</td>
                <td style="text-align: left;">{{ item.custom_item_specs or "" }}</td>
                <td style="text-align: center;" class="nowrap-col">{{ item.uom }}</td>
                <td style="text-align: right;" class="nowrap-col">{{ format_vn_num(item.qty) }}</td>
                <td style="text-align: right;" class="nowrap-col">{{ format_vn_num(item.rate) }}</td>
                <td style="text-align: center;" class="nowrap-col">
                    {% if tax_rate > 0 %}
                    {{ tax_rate | round | int }}%
                    {% else %}
                    0%
                    {% endif %}
                </td>
                <td style="text-align: right;" class="nowrap-col">{{ format_vn_num(rate_with_vat) }}</td>
                <td style="text-align: right;" class="nowrap-col">{{ format_vn_num(amount_with_vat) }}</td>
                <td style="text-align: left;">{{ item.warehouse | replace(' - DHC', '') }}</td>
                <td style="text-align: left;">{{ item.custom_invoice_name or "" }}</td>
                <td style="text-align: left;">
                    {% if item.description and item.description != item.item_name %}
                    {{ item.description | striptags }}
                    {% endif %}
                </td>
            </tr>
            {% endfor %}
            <tr class="total-row">
                <td colspan="9" style="text-align: center; font-weight: bold; text-transform: uppercase;">TỔNG CỘNG</td>
                <td style="text-align: right; font-weight: bold;">{{ format_vn_num(doc.grand_total) }}</td>
                <td colspan="3"></td>
            </tr>
        </tbody>
    </table>

    <!-- Agreements Section -->
    <div class="agreements-section">
        <div class="agreement-title">* Thoả thuận khác:</div>

        <div class="agreement-item">
            <span class="item-num">1. Thời gian thanh toán/ Số ngày công nợ:</span>
            <span class="item-val">{{ doc.payment_terms_template or "Công nợ 30 ngày" }}</span>
        </div>

        <div class="agreement-item">
            <span class="item-num">2. Thời gian nhận hóa đơn:</span>
            <span class="item-val">{{ doc.custom_invoice_receive_time or "Chậm nhất 24h kể từ khi nhận hàng" }}</span>
        </div>

        <div class="agreement-item">
            <span class="item-num">3. Thông tin nhận hàng:</span>
            <div class="sub-item">- Phương thức giao nhận: {{ doc.custom_delivery_method or "" }}</div>
            <div class="sub-item">- Nơi giao: {{ doc.custom_delivery_place or doc.supplier_name or "" }}</div>
            <div class="sub-item">- Địa chỉ: {{ doc.shipping_address_display or "" }}</div>
            <div class="sub-item">- Người liên hệ bên mua: {{ doc.custom_buyer_contact or "" }}</div>
        </div>

        <div class="agreement-item">
            <span class="item-num">4. Thông tin nhận hóa đơn:</span>
            <div class="sub-item">- Tên đơn vị: {{ (company_doc.company_name or doc.company) | upper }}</div>
            <div class="sub-item">- Mã số thuế: {{ company_doc.tax_id or "" }}</div>
            <div class="sub-item">- Địa chỉ: {{ company_address_display or "Chưa cấu hình địa chỉ công ty" }}</div>
            <div class="sub-item">- Mail nhận hóa đơn: {{ doc.custom_billing_email or company_doc.email or
                "phongsanxuat.luutru@gmail.com" }}</div>
        </div>

        <div class="attached-info">
            <strong>Các thông tin, file, hình ảnh gửi kèm đơn hàng:</strong> {{ doc.custom_attached_info or "" }}
        </div>

        {% if doc.terms %}
        <div class="attached-info" style="margin-top: 15px;">
            <strong>Ghi chú / Điều khoản khác:</strong>
            <div style="margin-left: 20px; margin-top: 5px; font-style: italic;">{{ doc.terms }}</div>
        </div>
        {% endif %}
    </div>

    <!-- Signatures -->
    <div class="signature-section">
        <table class="signature-table">
            <tr>
                <td style="width: 50%;"></td>
                <td style="width: 50%; text-align: center; font-style: italic;">Cần Thơ, ngày {{ trans_date.day }} tháng {{ trans_date.month }} năm {{ trans_date.year }}</td>
            </tr>
            <tr>
                <td style="text-align: center; font-weight: bold;">Trưởng bộ phận</td>
                <td style="text-align: center; font-weight: bold;">Người lập</td>
            </tr>
            <tr style="height: 80px;">
                <td></td>
                <td></td>
            </tr>
        </table>
    </div>
</div>
